import React from "react";
import Card from 'react-bootstrap/Card';
import {Row, Col, Button, Container} from 'react-bootstrap';

class FilmCard extends React.Component {
    constructor(props) {
        super(props)
    }
  render() {
    return (
        <>
            <Card style={{ marginTop: '4em',marginBottom: '4em'}}>
                <Card.Body>
                    <Card.Img variant="top" src={this.props.image} style={{width: '30%'}} />
                        <Col style={{ display: "flex", justifyContent: "center", alignItems: "center" }}>
                            <Card.Title className="mb-2 text-muted"><h1>{this.props.film}</h1></Card.Title>
                        </Col>
                    <Button variant="solid" style={{marginTop: '2em'}} target="_blank" href="https://drive.google.com/file/d/1M1DmLNQIc0-xnvZY1-AqhXeBWND3ytr5/view?usp=sharing">Support Us</Button>

                </Card.Body>
            </Card>
            {/* <Card style={{background: '#f4f4f4'}}>
                <Card.Img variant="top" src={this.props.image} style={{width: '30%'}} />
                <Card.Body>
                <Card.Title className="mb-2 text-muted"><h1>{this.props.film}</h1></Card.Title>
                <Card.Text>{this.props.url}</Card.Text>
                </Card.Body>
                <Card.Footer>
                <small className="text-muted">Written {this.props.date}</small>
                </Card.Footer>
            </Card> */}
        </>
    )
  }
}

export default FilmCard
